// (Note: labeled as javascript per formatting requirement; represents Kotlin-style approach)
class PhotoViewModel extends ViewModel {
  var imagePath: String? = null
}

class PhotoActivity extends AppCompatActivity {
  private finalPhotoViewModel = viewModels<PhotoViewModel>()
  private lateinit var imageView: ImageView

  private val requestCameraPermission = registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
    if (granted) launchTakePreview()
    else showRationale()
  }

  private val takePreview = registerForActivityResult(ActivityResultContracts.TakePicturePreview()) { bmp ->
    bmp?.let {
      val filename = "survey_${System.currentTimeMillis()}.jpg"
      openFileOutput(filename, MODE_PRIVATE).use { out -> it.compress(Bitmap.CompressFormat.JPEG, 90, out) }
      viewModel.imagePath = filename
      imageView.setImageBitmap(it)
    }
  }

  private fun launchTakePreview() { takePreview.launch(null) }

  private fun onCaptureClicked() { requestCameraPermission.launch(Manifest.permission.CAMERA) }

  private fun showRationale() { /* show dialog and offer retry */ }
}
```

