## Code Example
```kotlin
// Multi-user Room shard with per-user encryption
@Entity(tableName = "user_data")
data class UserData(
    @PrimaryKey val id: Long,
    val userId: Int,
    val payload: ByteArray
)

class EncryptedUserShard(
    private val userId: Int,
    private val keyStore: AndroidKeyStore
) {
    private val keyAlias = "user_shard_key_$userId"
    private val db: UserDatabase by lazy {
        val key = getOrCreateUserKey(keyAlias)
        Room.databaseBuilder(
            appContext,
            UserDatabase::class.java,
            "user_shard_$userId.db"
        )
        .openHelperFactory(SQLCipherOpenHelperFactory(key))
        .build()
    }

    private fun getOrCreateUserKey(alias: String): ByteArray {
        if (!keyStore.containsAlias(alias)) {
            val keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES, "AndroidKeyStore"
            )
            val spec = KeyGenParameterSpec.Builder(
                alias,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setUserAuthenticationRequired(true)
            .build()
            keyGenerator.init(spec)
            keyGenerator.generateKey()
        }
        return keyStore.getKey(alias, null).encoded
    }
}

// Binder service with user context validation
interface IUserDataService {
    fun getData(userId: Int, key: String): List<UserData>
    fun setData(userId: Int, data: UserData)
    fun migrateUserData(fromUserId: Int, toUserId: Int)
    fun switchUser(targetUserId: Int): Boolean
}

class UserDataService : IUserDataService {
    private val userSessionCache = LruCache<Int, UserSession>(5)

    private fun validateUserContext(callingUid: Int, requestedUserId: Int): Boolean {
        val context = ActivityManager.getService().getUserInfo(
            UserHandle.getUserId(callingUid)
        )
        return context.id == requestedUserId
    }

    override fun getData(userId: Int, key: String): List<UserData> {
        if (!validateUserContext(Binder.getCallingUid(), userId)) {
            throw SecurityException("User context mismatch")
        }
        return getShard(userId).userDataDao().getByKey(key)
    }

    override fun switchUser(targetUserId: Int): Boolean {
        val startTime = SystemClock.elapsedRealtime()
        // Pre-warm target user's shard
        val session = userSessionCache.get(targetUserId) 
            ?: UserSession(targetUserId).also { userSessionCache.put(targetUserId, it) }
        session.activate()
        val switchTime = SystemClock.elapsedRealtime() - startTime
        return switchTime < 100 // Enforce sub-100ms target
    }
}
```

## Data Migration Strategy
1. Export source user's encrypted shard to intermediate storage
2. Re-encrypt with target user's Keystore key
3. Import into target user's shard
4. Verify integrity via checksum
5. Securely wipe source data

