// Kotlin-like pseudocode
@Entity(tableName = "events")
data class Event(
  @PrimaryKey val id: String,
  val screen: String,
  val action: String,
  val ts: Long,
  val synced: Boolean = false
)

@Dao
interface EventDao {
  @Insert(onConflict = REPLACE)
  suspend fun insertEvent(event: Event)

  @Query("SELECT * FROM events WHERE synced = 0 LIMIT :limit")
  suspend fun getUnsynced(limit: Int): List<Event>

  @Query("UPDATE events SET synced = 1 WHERE id IN (:ids)")
  suspend fun markSynced(ids: List<String>)
}

class EventRepository(private val dao: EventDao) {
  suspend fun saveEvent(screen: String, action: String) {
    dao.insertEvent(Event(UUID.randomUUID().toString(), screen, action, System.currentTimeMillis()))
    enqueueBatch()
  }

  private fun enqueueBatch() {
    WorkManager.getInstance().enqueueUniqueWork(
      "EventUpload",
      ExistingWorkPolicy.REPLACE,
      OneTimeWorkRequestBuilder<EventUploadWorker>()
        .setConstraints(Constraints.Builder().setRequiredNetworkType(NetworkType.CONNECTED).build())
        .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 30, TimeUnit.SECONDS)
        .build()
    )
  }
}

class EventUploadWorker(appContext: Context, workerParams: WorkerParameters) : CoroutineWorker(appContext, workerParams) {
  override suspend fun doWork(): Result {
    val dao = EventDatabase.getInstance(applicationContext).eventDao()
    val batchSize = 50

    return try {
      val events = dao.getUnsynced(batchSize)
      if (events.isEmpty()) return Result.success()

      apiClient.uploadEvents(events)
      dao.markSynced(events.map { it.id })
      Result.success()
    } catch (e: Exception) {
      Result.retry()
    }
  }
}
```

