// Pseudocode: last-write-wins merge for edits
function mergeEdits(local, remote) {
  const out = { ...remote };
  for (const key of Object.keys(local)) {
    const l = local[key];
    const r = remote[key];
    out[key] = (l?.ts > r?.ts) ? l.value : r.value;
  }
  return out;
}
