// Base module: Stable interface all plugins must implement
@Retention(AnnotationRetention.RUNTIME)
@Target(AnnotationTarget.CLASS, AnnotationTarget.FUNCTION)
annotation class PluginVersion(val major: Int, val minor: Int, val patch: Int)

