    fun initialize(context: Context)
    fun getFeatures(): List<PluginFeature>
    fun onDestroy()
}

// Version compatibility checker
object PluginVersionChecker {
    fun isCompatible(requested: PluginVersion, available: PluginVersion): Boolean {
        return requested.major == available.major && 
               requested.minor <= available.minor
    }
}

// ProGuard rules to preserve interfaces:
// -keep class com.app.base.plugin.** { *; }
