### 2. Module Isolation with Custom ClassLoaders

```kotlin
class IsolatedModuleLoader(
    private val context: Context,
    private val moduleName: String
) {
    private var classLoader: ClassLoader? = null

    fun loadModule(modulePath: String): PluginApi? {
        val apkFile = File(context.filesDir, "modules/$modulePath.apk")

        // Verify SHA256 hash before loading
        if (!verifyModuleIntegrity(apkFile)) {
            return null
        }

        classLoader = CustomClassLoader(
            apkFile.absolutePath,
            context.classLoader.parent,
            moduleName
        )

        val clazz = classLoader!!.loadClass("com.plugin.FeatureModule")
        return clazz.newInstance() as PluginApi
    }

    private fun verifyModuleIntegrity(apkFile: File): Boolean {
        val digest = MessageDigest.getInstance("SHA-256")
        val hash = digest.digest(apkFile.readBytes())
            .joinToString("") { "%02x".format(it) }
        return hash == getExpectedHash(moduleName)
    }

    fun unload() {
        classLoader = null
        System.gc()
    }
}
```

