### 5. Offline Manifest Caching

```kotlin
@Entity(tableName = "feature_manifest")
data class CachedManifest(
    @PrimaryKey val featureId: String,
    val version: String,
    val downloadUrl: String,
    val sha256Hash: String,
    val sizeBytes: Long,
    val dependencies: String, // JSON array
    val cachedAt: Long,
    val expiresAt: Long
)

class ManifestCacheManager(
    private val dao: ManifestDao,
    private val networkApi: FeatureManifestApi
) {
    suspend fun getManifest(featureId: String): CachedManifest? {
        val cached = dao.getManifest(featureId)
        if (cached != null && !isExpired(cached)) {
            return cached
        }

        // Try network fetch if online
        return try {
            val remote = networkApi.fetchManifest(featureId)
            dao.insert(remote)
            remote
        } catch (e: Exception) {
            // Return stale cache as fallback
            cached?.takeIf { isStaleButUsable(it) }
        }
    }

    private fun isExpired(manifest: CachedManifest): Boolean {
        return System.currentTimeMillis() > manifest.expiresAt
    }
}
```

### 6. Dynamic Module Installation with Rollback

```kotlin
class DynamicModuleInstaller(
    private val splitInstallManager: SplitInstallManager
) {
    private val moduleVersionHistory = mutableMapOf<String, String>()

    suspend fun installModule(
        featureId: String,
        version: String,
        onProgress: (Int) -> Unit
    ): Result<Unit> {
        val sessionParams = SplitInstallSessionParams.Builder()
            .setModuleNames(listOf(featureId))
            .setInstallStrategy(InstallStrategy.IDLE)
            // Defer until charging + WiFi for battery-conscious behavior
            .setRequiresCharging(true)
            .setRequiresWifi(true)
            .build()

        val request = SplitInstallRequest.Builder()
            .addModule(featureId)
            .setSessionParams(sessionParams)
            .build()

        return splitInstallManager.startInstallation(request)
            .addOnSuccessListener { sessionId -> 
                moduleVersionHistory[featureId] = version
                saveVersionHistory()
            }
            .addOnFailureListener { e -> 
                // Rollback handled by Play Store automatically
                // Additional custom rollback:
                performRollback(featureId)
            }
    }

    suspend fun performRollback(featureId: String) {
        // Record rollback in history
        moduleVersionHistory.remove(featureId)
        saveVersionHistory()

        // Uninstall problematic module
        splitInstallManager.deferredUninstall(listOf(featureId))

        // Load fallback UI from base module
        loadFallbackFeature(featureId)
    }

    fun loadFallbackFeature(featureId: String): Fragment {
        return when (featureId) {
            "advanced_analytics" -> AnalyticsFallbackFragment()
            "video_processing" -> VideoFallbackFragment()
            else -> DefaultFallbackFragment()
        }
    }
}
```

