class LoginState(
  val email: String = "",
  val password: String = "",
  val emailError: String? = null,
  val passwordError: String? = null,
  val loading: Boolean = false,
  val loginResult: Boolean? = null
)

class LoginViewModel : ViewModel() {
  private val _state = MutableStateFlow(LoginState())
  val state: StateFlow<LoginState> = _state

  private fun validateEmail(email: String): String? =
    if (android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches()) null else "Invalid email"
  private fun validatePassword(pw: String): String? =
    if (pw.length >= 8) null else "Password too short"

  fun onEmailChange(e: String) {
    _state.value = _state.value.copy(email = e, emailError = validateEmail(e))
  }

  fun onPasswordChange(pw: String) {
    _state.value = _state.value.copy(password = pw, passwordError = validatePassword(pw))
  }

  fun login() {
    val s = _state.value
    val e = s.emailError
    val p = s.passwordError
    if (e != null || p != null) return
    _state.value = s.copy(loading = true)
    viewModelScope.launch {
      val ok = FakeAuthRepository.login(s.email, s.password)
      _state.value = s.copy(loading = false, loginResult = ok)
    }
  }
}
```

